mapper.select:
SELECT COUNT(*) FROM cmt c LEFT JOIN course_trip ct ON c.TRIP_COURSE_NO = ct.COURSE_NO WHERE 1 = 1
AND c.CMT_CN LIKE '%' || #{searchWord} || '%'
AND c.TRIP_COURSE_NO = #{searchWord}
AND c.CMT_HIDE_YN = #{searchWord}

SELECT * FROM ( SELECT ROWNUM AS rnum, T1.* FROM ( SELECT c.CMT_NO AS "cmtNo", c.CMT_CN AS "cmtCn", c.CMT_STARNG AS "cmtStarng", c.CMT_CLSF AS "cmtClsf", c.CMT_HIDE_YN AS "cmtHideYn", c.TRIP_COURSE_NO AS "tripCourseNo", c.CMT_REG AS "cmtReg", c.CMT_MOD AS "cmtMod", ct.TRIP_CONTS_ID AS "tripContsId" FROM cmt c LEFT JOIN course_trip ct ON c.TRIP_COURSE_NO = ct.COURSE_NO WHERE 1 = 1
AND c.CMT_CN LIKE '%' || #{searchWord} || '%'
AND c.TRIP_COURSE_NO = #{searchWord}
AND c.CMT_HIDE_YN = #{searchWord}
ORDER BY c.CMT_NO DESC ) T1 WHERE ROWNUM <= #{pageSize} * (#{pageNo} - 1) + #{pageSize} ) WHERE rnum >= #{pageSize} * (#{pageNo} - 1) + 1
